'use client';

import React, { createContext, useContext, useEffect, useState } from 'react';
import {
  isRunningAsPWA,
  getDisplayMode,
  isIOSDevice,
  isIOSPWA,
} from '@/lib/pwa/detect-pwa';

interface PWAContextType {
  isPWA: boolean;
  displayMode: 'standalone' | 'fullscreen' | 'minimal-ui' | 'browser';
  isIOSDevice: boolean;
  isIOSPWA: boolean;
  isInitialized: boolean;
}

const PWAContext = createContext<PWAContextType | undefined>(undefined);

export function PWAProvider({ children }: { children: React.ReactNode }) {
  const [pwaStatus, setPwaStatus] = useState<PWAContextType>({
    isPWA: false,
    displayMode: 'browser',
    isIOSDevice: false,
    isIOSPWA: false,
    isInitialized: false,
  });

  useEffect(() => {
    // Detect PWA status on mount (client-side only)
    setPwaStatus({
      isPWA: isRunningAsPWA(),
      displayMode: getDisplayMode(),
      isIOSDevice: isIOSDevice(),
      isIOSPWA: isIOSPWA(),
      isInitialized: true,
    });

    // Apply .pwa class to body for CSS hooks
    if (isRunningAsPWA()) {
      document.body.classList.add('pwa');
    } else {
      document.body.classList.remove('pwa');
    }
  }, []);

  return (
    <PWAContext.Provider value={pwaStatus}>{children}</PWAContext.Provider>
  );
}

/**
 * Hook to access PWA context throughout the app
 * Returns the current PWA detection status
 */
export function usePWA(): PWAContextType {
  const context = useContext(PWAContext);

  if (context === undefined) {
    throw new Error('usePWA must be used within a PWAProvider');
  }

  return context;
}

/**
 * Convenience hook: Is the app running as PWA?
 */
export function useIsPWA(): boolean {
  const { isPWA, isInitialized } = usePWA();
  return isInitialized && isPWA;
}

/**
 * Convenience hook: Is the app running on iOS PWA?
 */
export function useIsIOSPWA(): boolean {
  const { isIOSPWA, isInitialized } = usePWA();
  return isInitialized && isIOSPWA;
}

'use client';

import { gsap, useGSAP } from '../../../lib/gsap';

export const HomeTransitions = () => {
  useGSAP(() => {
    const media = gsap.matchMedia();

    media.add('(prefers-reduced-motion: no-preference)', () => {
      const productsSection = document.querySelector<HTMLElement>('[data-home-products]');

      if (!productsSection) {
        return;
      }

      gsap.set(productsSection, { willChange: 'transform, opacity' });

      const tween = gsap.fromTo(
        productsSection,
        {
          y: 56,
          autoAlpha: 0.94,
        },
        {
          y: 0,
          autoAlpha: 1,
          ease: 'none',
          scrollTrigger: {
            trigger: productsSection,
            start: 'top 92%',
            end: 'top 68%',
            scrub: 0.8,
            fastScrollEnd: true,
            invalidateOnRefresh: true,
          },
        }
      );

      return () => {
        tween.scrollTrigger?.kill();
        tween.kill();
        gsap.set(productsSection, { clearProps: 'willChange' });
      };
    });

    return () => media.revert();
  });

  return null;
};

'use client';

import { gsap, useGSAP } from '../../../lib/gsap';

export const HomeTransitions = () => {
  useGSAP(() => {
    const media = gsap.matchMedia();

    media.add('(prefers-reduced-motion: no-preference)', () => {
      const productsSection = document.querySelector<HTMLElement>('[data-home-products]');

      if (!productsSection) {
        return;
      }

      gsap.set(productsSection, { willChange: 'transform, opacity' });

      const tween = gsap.fromTo(
        productsSection,
        {
          y: 56,
          autoAlpha: 0.94,
        },
        {
          y: 0,
          autoAlpha: 1,
          ease: 'none',
          scrollTrigger: {
            trigger: productsSection,
            start: 'top 92%',
            end: 'top 68%',
            scrub: 0.8,
            fastScrollEnd: true,
            invalidateOnRefresh: true,
          },
          onComplete: () => {
            // Clear will-change after animation completes for better performance
            gsap.set(productsSection, { clearProps: 'willChange' });
          },
        }
      );

      return () => {
        tween.scrollTrigger?.kill();
        tween.kill();
        // Ensure cleanup of all animation properties set by GSAP
        gsap.set(productsSection, { clearProps: 'all' });
      };
    });

    return () => media.revert();
  });

  return null;
};
